-- Seed Lessons for Python Variables & Data Types
INSERT INTO lessons (topic_id, title, content, code_example, exercise, order_index) VALUES
((SELECT id FROM topics WHERE title = 'Variables & Data Types' AND language_id = (SELECT id FROM languages WHERE slug = 'python')), 'Introduction to Variables', 'Variables are containers for storing data values. In Python, you don''t need to declare a variable type.', 'x = 5\nname = "Alice"\nis_student = True\nprint(x, name, is_student)', 'Create variables for your name, age, and whether you are a student. Print them all.', 1) ON CONFLICT DO NOTHING;
INSERT INTO lessons (topic_id, title, content, code_example, exercise, order_index) VALUES
((SELECT id FROM topics WHERE title = 'Variables & Data Types' AND language_id = (SELECT id FROM languages WHERE slug = 'python')), 'Numbers and Strings', 'Python supports integers, floats, and complex numbers. Strings are sequences of characters.', 'age = 25\npi = 3.14159\ngreeting = "Hello, World!"\nprint(type(age), type(pi), type(greeting))', 'Calculate the area of a circle with radius 7 and store it in a variable.', 2) ON CONFLICT DO NOTHING;



