INSERT INTO problems (title, description, difficulty, input_format, output_format, function_signatures, test_cases, expected_output, points, category, wrapper_config) VALUES
('Sum of Array Elements', 'Calculate the collective sum of all numerical elements stored within a given zero-indexed integer array. This is a fundamental exercise in iterative traversal and accumulation.', 'Easy', 'An integer n representing the size of the array, followed by n space-separated integers representing the array elements.', 'A single integer representing the total sum of the array elements.', '{"python":"def sumArray(n, nums):\n    pass","java":"class Solution {\n    public int sumArray(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    int sumArray(int n, vector<int>& nums) {\n        \n    }\n};","c":"int sumArray(int n, int* nums) {\n    \n}","javascript":"var sumArray = function(n, nums) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5", "expected": "15", "sample": true}, {"input": "1\n10", "expected": "10", "sample": true}, {"input": "3\n0 0 0", "expected": "0", "sample": true}, {"input": "2\n-1 -1", "expected": "-2", "sample": false}, {"input": "4\n1 2 3 4", "expected": "10", "sample": false}, {"input": "5\n-5 -4 -3 -2 -1", "expected": "-15", "sample": false}, {"input": "2\n1000 -1000", "expected": "0", "sample": false}, {"input": "3\n5 10 15", "expected": "30", "sample": false}, {"input": "4\n0 1 2 3", "expected": "6", "sample": false}, {"input": "5\n10 20 30 40 50", "expected": "150", "sample": false}, {"input": "1\n0", "expected": "0", "sample": false}, {"input": "2\n42 42", "expected": "84", "sample": false}, {"input": "3\n123 456 789", "expected": "1368", "sample": false}, {"input": "4\n-10 20 -30 40", "expected": "20", "sample": false}, {"input": "5\n1 1 1 1 1", "expected": "5", "sample": false}]', '15', 10, 'Arrays', '{"functionName":"sumArray","returnType":"int","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Find Maximum Element', 'Identify and return the largest integer value present in the provided array. If the array contains duplicate maximums, returning the value itself is sufficient. This problem focuses on single-pass comparison logic.', 'Easy', 'An integer n representing the size of the array, followed by n space-separated integers.', 'A single integer representing the maximum value found in the array.', '{"python":"def findMax(n, nums):\n    pass","java":"class Solution {\n    public int findMax(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    int findMax(int n, vector<int>& nums) {\n        \n    }\n};","c":"int findMax(int n, int* nums) {\n    \n}","javascript":"var findMax = function(n, nums) {\n    \n};"}', '[{"input": "4\n10 5 20 8", "expected": "20", "sample": true}, {"input": "1\n5", "expected": "5", "sample": true}, {"input": "2\n-1 -5", "expected": "-1", "sample": true}, {"input": "3\n0 0 0", "expected": "0", "sample": false}, {"input": "4\n100 200 50 150", "expected": "200", "sample": false}, {"input": "5\n-10 -20 -30 -40 -50", "expected": "-10", "sample": false}, {"input": "6\n1 1 1 1 1 1", "expected": "1", "sample": false}, {"input": "2\n10 10", "expected": "10", "sample": false}, {"input": "3\n7 14 21", "expected": "21", "sample": false}, {"input": "4\n42 17 88 3", "expected": "88", "sample": false}, {"input": "5\n5 4 3 2 1", "expected": "5", "sample": false}, {"input": "6\n10 20 30 40 50 60", "expected": "60", "sample": false}, {"input": "3\n-5 0 5", "expected": "5", "sample": false}, {"input": "4\n99 100 101 98", "expected": "101", "sample": false}, {"input": "5\n123 456 789 0 111", "expected": "789", "sample": false}]', '20', 10, 'Arrays', '{"functionName":"findMax","returnType":"int","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Count Even and Odd Numbers', 'Determine the frequency of even and odd integers within a given collection. An even number is divisible by 2 without a remainder, while an odd number is not.', 'Easy', 'An integer n followed by n space-separated integers.', 'Two space-separated integers: the count of even numbers and the count of odd numbers, in that order.', '{"python":"def countEvenOdd(n, nums):\n    pass","java":"class Solution {\n    public int[] countEvenOdd(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    pair<int, int> countEvenOdd(int n, vector<int>& nums) {\n        \n    }\n};","c":"void countEvenOdd(int n, int* nums, int* even, int* odd) {\n    \n}","javascript":"var countEvenOdd = function(n, nums) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5", "expected": "2 3", "sample": true}, {"input": "1\n2", "expected": "1 0", "sample": true}, {"input": "1\n3", "expected": "0 1", "sample": true}, {"input": "2\n2 4", "expected": "2 0", "sample": false}, {"input": "2\n1 3", "expected": "0 2", "sample": false}, {"input": "3\n1 2 3", "expected": "1 2", "sample": false}, {"input": "4\n0 0 0 0", "expected": "4 0", "sample": false}, {"input": "5\n-2 -1 0 1 2", "expected": "3 2", "sample": false}, {"input": "6\n10 20 30 40 50 61", "expected": "5 1", "sample": false}, {"input": "2\n7 8", "expected": "1 1", "sample": false}, {"input": "3\n42 17 88", "expected": "2 1", "sample": false}, {"input": "4\n1 1 1 1", "expected": "0 4", "sample": false}, {"input": "5\n2 2 2 2 2", "expected": "5 0", "sample": false}, {"input": "3\n123 456 789", "expected": "1 2", "sample": false}, {"input": "4\n10 11 12 13", "expected": "2 2", "sample": false}]', '2 3', 10, 'Arrays', '{"functionName":"countEvenOdd","returnType":"int[]","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Reverse an Array', 'Reorganize the elements of the provided array such that the first element becomes the last, the second becomes the second-to-last, and so forth. This operation should be performed by creating a new sequence or modifying the existing one.', 'Easy', 'An integer n followed by n integers.', 'The elements of the array in reversed order, separated by spaces.', '{"python":"def reverseArray(n, nums):\n    pass","java":"class Solution {\n    public int[] reverseArray(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    vector<int> reverseArray(int n, vector<int>& nums) {\n        \n    }\n};","c":"int* reverseArray(int n, int* nums) {\n    \n}","javascript":"var reverseArray = function(n, nums) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5", "expected": "5 4 3 2 1", "sample": true}, {"input": "1\n10", "expected": "10", "sample": true}, {"input": "2\n1 2", "expected": "2 1", "sample": true}, {"input": "3\n0 0 0", "expected": "0 0 0", "sample": false}, {"input": "4\n-1 -2 -3 -4", "expected": "-4 -3 -2 -1", "sample": false}, {"input": "5\n10 20 30 40 50", "expected": "50 40 30 20 10", "sample": false}, {"input": "2\n7 7", "expected": "7 7", "sample": false}, {"input": "3\n1 3 5", "expected": "5 3 1", "sample": false}, {"input": "4\n42 17 88 3", "expected": "3 88 17 42", "sample": false}, {"input": "5\n5 4 3 2 1", "expected": "1 2 3 4 5", "sample": false}, {"input": "6\n1 1 1 1 1 1", "expected": "1 1 1 1 1 1", "sample": false}, {"input": "3\n-5 0 5", "expected": "5 0 -5", "sample": false}, {"input": "2\n100 200", "expected": "200 100", "sample": false}, {"input": "4\n99 100 101 98", "expected": "98 101 100 99", "sample": false}, {"input": "5\n123 456 789 0 111", "expected": "111 0 789 456 123", "sample": false}]', '5 4 3 2 1', 10, 'Arrays', '{"functionName":"reverseArray","returnType":"int[]","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Check Palindrome String', 'Verify if a given string reads identical both forwards and backwards, maintaining consistent character sequencing. This involves comparing the string with its inverse.', 'Easy', 'A single non-empty string s.', 'Return YES if the string is a palindrome, otherwise return NO.', '{"python":"def isPalindrome(s):\n    pass","java":"class Solution {\n    public String isPalindrome(String s) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    string isPalindrome(string s) {\n        \n    }\n};","c":"char* isPalindrome(char* s) {\n    \n}","javascript":"var isPalindrome = function(s) {\n    \n};"}', '[{"input": "madam", "expected": "YES", "sample": true}, {"input": "hello", "expected": "NO", "sample": true}, {"input": "a", "expected": "YES", "sample": true}, {"input": "racecar", "expected": "YES", "sample": false}, {"input": "noon", "expected": "YES", "sample": false}, {"input": "level", "expected": "YES", "sample": false}, {"input": "world", "expected": "NO", "sample": false}, {"input": "abcba", "expected": "YES", "sample": false}, {"input": "abccba", "expected": "YES", "sample": false}, {"input": "kayak", "expected": "YES", "sample": false}, {"input": "deed", "expected": "YES", "sample": false}, {"input": "radar", "expected": "YES", "sample": false}, {"input": "civic", "expected": "YES", "sample": false}, {"input": "steponnopets", "expected": "YES", "sample": false}, {"input": "abcde", "expected": "NO", "sample": false}]', 'YES', 10, 'Strings', '{"functionName":"isPalindrome","returnType":"string","params":[{"name":"s","type":"str"}]}'),

('Sum of Even Numbers in Array', 'Isolate and aggregate all even integers contained within the given array. The resulting sum should represent the total of only those numbers that are divisible by 2.', 'Easy', 'An integer n followed by n space-separated integers.', 'A single integer representing the sum of all even elements.', '{"python":"def sumEven(n, nums):\n    pass","java":"class Solution {\n    public int sumEven(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    int sumEven(int n, vector<int>& nums) {\n        \n    }\n};","c":"int sumEven(int n, int* nums) {\n    \n}","javascript":"var sumEven = function(n, nums) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5", "expected": "6", "sample": true}, {"input": "3\n1 3 5", "expected": "0", "sample": true}, {"input": "4\n2 4 6 8", "expected": "20", "sample": true}, {"input": "1\n2", "expected": "2", "sample": false}, {"input": "1\n3", "expected": "0", "sample": false}, {"input": "5\n0 0 0 0 0", "expected": "0", "sample": false}, {"input": "3\n-2 -4 -6", "expected": "-12", "sample": false}, {"input": "4\n-1 -2 -3 -4", "expected": "-6", "sample": false}, {"input": "6\n10 21 32 43 54 65", "expected": "96", "sample": false}, {"input": "2\n7 8", "expected": "8", "sample": false}, {"input": "5\n100 200 300 400 500", "expected": "1500", "sample": false}, {"input": "3\n11 22 33", "expected": "22", "sample": false}, {"input": "4\n1 1 1 1", "expected": "0", "sample": false}, {"input": "2\n42 42", "expected": "84", "sample": false}, {"input": "5\n10 10 10 10 10", "expected": "50", "sample": false}]', '6', 10, 'Arrays', '{"functionName":"sumEven","returnType":"int","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Check if Array is Sorted', 'Examine the provided integer array and determine whether it is organized in non-decreasing order. An array is considered sorted if every element is less than or equal to the element that immediately follows it.', 'Easy', 'An integer n followed by n space-separated integers.', 'Return YES if the array is sorted in non-decreasing order, otherwise return NO.', '{"python":"def isSorted(n, nums):\n    pass","java":"class Solution {\n    public String isSorted(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    string isSorted(int n, vector<int>& nums) {\n        \n    }\n};","c":"char* isSorted(int n, int* nums) {\n    \n}","javascript":"var isSorted = function(n, nums) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5", "expected": "YES", "sample": true}, {"input": "5\n5 4 3 2 1", "expected": "NO", "sample": true}, {"input": "1\n10", "expected": "YES", "sample": true}, {"input": "2\n1 1", "expected": "YES", "sample": false}, {"input": "3\n1 3 2", "expected": "NO", "sample": false}, {"input": "4\n-5 -4 -3 -2", "expected": "YES", "sample": false}, {"input": "3\n10 20 15", "expected": "NO", "sample": false}, {"input": "2\n100 200", "expected": "YES", "sample": false}, {"input": "5\n1 2 2 4 5", "expected": "YES", "sample": false}, {"input": "4\n100 100 100 100", "expected": "YES", "sample": false}, {"input": "3\n1 2 3", "expected": "YES", "sample": false}, {"input": "6\n1 2 3 4 5 0", "expected": "NO", "sample": false}, {"input": "2\n-10 0", "expected": "YES", "sample": false}, {"input": "4\n1 2 3 3", "expected": "YES", "sample": false}, {"input": "3\n5 5 4", "expected": "NO", "sample": false}]', 'YES', 10, 'Arrays', '{"functionName":"isSorted","returnType":"string","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Linear Search', 'Conduct a sequential search through the given array to locate a specific target value. If the target exists at any index within the array, return YES; if the end of the array is reached without locating the target, return NO.', 'Easy', 'An integer n, followed by n space-separated integers, and finally the target integer value.', 'Return YES if the target exists in the array, otherwise return NO.', '{"python":"def findTarget(n, nums, target):\n    pass","java":"class Solution {\n    public String findTarget(int n, int[] nums, int target) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    string findTarget(int n, vector<int>& nums, int target) {\n        \n    }\n};","c":"char* findTarget(int n, int* nums, int target) {\n    \n}","javascript":"var findTarget = function(n, nums, target) {\n    \n};"}', '[{"input": "5\n1 2 3 4 5\n3", "expected": "YES", "sample": true}, {"input": "3\n10 20 30\n40", "expected": "NO", "sample": true}, {"input": "1\n5\n5", "expected": "YES", "sample": true}, {"input": "2\n1 2\n3", "expected": "NO", "sample": false}, {"input": "4\n-1 -2 -3 -4\n-3", "expected": "YES", "sample": false}, {"input": "3\n0 0 0\n0", "expected": "YES", "sample": false}, {"input": "5\n10 20 30 40 50\n25", "expected": "NO", "sample": false}, {"input": "1\n0\n0", "expected": "YES", "sample": false}, {"input": "6\n1 3 5 7 9 11\n7", "expected": "YES", "sample": false}, {"input": "2\n7 8\n9", "expected": "NO", "sample": false}, {"input": "4\n42 17 88 3\n17", "expected": "YES", "sample": false}, {"input": "3\n100 200 300\n300", "expected": "YES", "sample": false}, {"input": "5\n1 1 1 1 1\n1", "expected": "YES", "sample": false}, {"input": "4\n2 4 6 8\n5", "expected": "NO", "sample": false}, {"input": "2\n-10 10\n10", "expected": "YES", "sample": false}]', 'YES', 10, 'Search', '{"functionName":"findTarget","returnType":"string","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"},{"name":"target","type":"int"}]}'),

('Count Zeros in Array', 'Count the total number of elements whose value is exactly zero. This problem assesses the ability to identify specific values during an iterative scan of a dataset.', 'Easy', 'An integer n followed by n integers.', 'The count of zero elements found in the array.', '{"python":"def countZeros(n, nums):\n    pass","java":"class Solution {\n    public int countZeros(int n, int[] nums) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    int countZeros(int n, vector<int>& nums) {\n        \n    }\n};","c":"int countZeros(int n, int* nums) {\n    \n}","javascript":"var countZeros = function(n, nums) {\n    \n};"}', '[{"input": "6\n0 1 0 3 0 5", "expected": "3", "sample": true}, {"input": "3\n1 2 3", "expected": "0", "sample": true}, {"input": "4\n0 0 0 0", "expected": "4", "sample": true}, {"input": "1\n0", "expected": "1", "sample": false}, {"input": "1\n5", "expected": "0", "sample": false}, {"input": "5\n0 1 2 0 3", "expected": "2", "sample": false}, {"input": "2\n0 0", "expected": "2", "sample": false}, {"input": "3\n0 10 0", "expected": "2", "sample": false}, {"input": "4\n-1 0 1 0", "expected": "2", "sample": false}, {"input": "6\n100 0 200 0 300 0", "expected": "3", "sample": false}, {"input": "2\n7 0", "expected": "1", "sample": false}, {"input": "5\n0 0 0 0 1", "expected": "4", "sample": false}, {"input": "3\n5 5 5", "expected": "0", "sample": false}, {"input": "4\n0 42 0 17", "expected": "2", "sample": false}, {"input": "1\n0", "expected": "1", "sample": false}]', '3', 10, 'Arrays', '{"functionName":"countZeros","returnType":"int","params":[{"name":"n","type":"int"},{"name":"nums","type":"json"}]}'),

('Sum of Digits', 'Determine the sum of every individual digit within a given integer. For example, if the input is 1234, the output should be 10 (1+2+3+4).', 'Easy', 'A single non-negative integer n.', 'A single integer representing the sum of all digits of n.', '{"python":"def sumDigits(n):\n    pass","java":"class Solution {\n    public int sumDigits(int n) {\n        \n    }\n}","cpp":"class Solution {\npublic:\n    int sumDigits(int n) {\n        \n    }\n};","c":"int sumDigits(int n) {\n    \n}","javascript":"var sumDigits = function(n) {\n    \n};"}', '[{"input": "1234", "expected": "10", "sample": true}, {"input": "5", "expected": "5", "sample": true}, {"input": "0", "expected": "0", "sample": true}, {"input": "100", "expected": "1", "sample": false}, {"input": "999", "expected": "27", "sample": false}, {"input": "123456789", "expected": "45", "sample": false}, {"input": "1111", "expected": "4", "sample": false}, {"input": "10101", "expected": "3", "sample": false}, {"input": "987654321", "expected": "45", "sample": false}, {"input": "567", "expected": "18", "sample": false}, {"input": "234", "expected": "9", "sample": false}, {"input": "888", "expected": "24", "sample": false}, {"input": "1000", "expected": "1", "sample": false}, {"input": "42", "expected": "6", "sample": false}, {"input": "314159", "expected": "23", "sample": false}]', '10', 10, 'Math', '{"functionName":"sumDigits","returnType":"int","params":[{"name":"n","type":"int"}]}')
