INSERT INTO problems (title, description, difficulty, input_format, output_format, function_signatures, test_cases, expected_output, points, category, wrapper_config) VALUES
('Maximum Element in Array', 'You are given an integer n representing the number of elements in an array, followed by n space-separated integers. Your task is to identify and print the maximum element present in the array.', 'Easy', 'First line: integer n
